import { GameConfig } from '../config/GameConfig';
import { FieldModel } from '../core/FieldModel';
import { GridPosition, SuperTileType, posKey } from '../core/Types';

// ══════════════════════════════════════════════════════════
//  Strategy interface (GoF Strategy)
// ══════════════════════════════════════════════════════════

/**
 * Determines the set of grid positions affected when a super‑tile activates.
 * Each concrete strategy corresponds to one SuperTileType.
 */
export interface ISuperTileStrategy {
    resolve(field: FieldModel, row: number, col: number): GridPosition[];
}

// ══════════════════════════════════════════════════════════
//  Concrete strategies
// ══════════════════════════════════════════════════════════

/** Destroy every tile in the same row. */
export class RowClearStrategy implements ISuperTileStrategy {
    public resolve(field: FieldModel, row: number, _col: number): GridPosition[] {
        return field.positionsInRow(row);
    }
}

/** Destroy every tile in the same column. */
export class ColumnClearStrategy implements ISuperTileStrategy {
    public resolve(field: FieldModel, _row: number, col: number): GridPosition[] {
        return field.positionsInColumn(col);
    }
}

/** Destroy tiles within a square radius. */
export class RadiusBombStrategy implements ISuperTileStrategy {
    constructor(private readonly radius: number) {}

    public resolve(field: FieldModel, row: number, col: number): GridPosition[] {
        return field.positionsInRadius(row, col, this.radius);
    }
}

/** Destroy every tile on the field. */
export class FieldClearStrategy implements ISuperTileStrategy {
    public resolve(field: FieldModel): GridPosition[] {
        return field.allNonNullPositions();
    }
}

// ══════════════════════════════════════════════════════════
//  Resolver (registry + chain helper)
// ══════════════════════════════════════════════════════════

/**
 * Central access point for super‑tile logic.
 *
 *  • Maps SuperTileType → concrete ISuperTileStrategy
 *  • Determines which super‑tile type a given group‑size produces
 *  • Collects chain‑reactions when one blast hits other super‑tiles
 */
export class SuperTileResolver {

    // ── Strategy registry (open/closed‑friendly) ──────────
    private static readonly strategies = new Map<SuperTileType, ISuperTileStrategy>([
        [SuperTileType.RowClear,    new RowClearStrategy()],
        [SuperTileType.ColumnClear, new ColumnClearStrategy()],
        [SuperTileType.RadiusBomb,  new RadiusBombStrategy(GameConfig.SUPER_BOMB_RADIUS)],
        [SuperTileType.FieldClear,  new FieldClearStrategy()],
    ]);

    // ── Resolve positions for a single super‑tile ─────────

    public static resolve(
        type: SuperTileType,
        field: FieldModel,
        row: number,
        col: number,
    ): GridPosition[] {
        const s = this.strategies.get(type);
        return s ? s.resolve(field, row, col) : [];
    }

    // ── Determine type from group size ────────────────────

    public static determineType(groupSize: number): SuperTileType {
        if (groupSize >= GameConfig.SUPER_FIELD_CLEAR_MIN)  return SuperTileType.FieldClear;
        if (groupSize >= GameConfig.SUPER_RADIUS_BOMB_MIN)  return SuperTileType.RadiusBomb;
        if (groupSize >= GameConfig.SUPER_COL_CLEAR_MIN)    return SuperTileType.ColumnClear;
        if (groupSize >= GameConfig.SUPER_ROW_CLEAR_MIN)    return SuperTileType.RowClear;
        return SuperTileType.None;
    }

    // ── Chain‑reaction collection ─────────────────────────
    /**
     * Starting from `seeds`, resolve every super‑tile caught in the blast
     * recursively.  Uses BFS to avoid infinite loops when two super‑tiles
     * overlap each other's areas.
     */
    public static collectChained(
        field: FieldModel,
        seeds: GridPosition[],
    ): GridPosition[] {
        const visited = new Set<string>();
        const result: GridPosition[] = [];
        const queue: Array<{ row: number; col: number; superType: SuperTileType }> = [];

        const enqueue = (p: GridPosition): void => {
            const k = posKey(p.row, p.col);
            if (visited.has(k)) return;
            visited.add(k);
            result.push(p);

            const cell = field.getCell(p.row, p.col);
            if (cell && cell.superType !== SuperTileType.None) {
                queue.push({ row: p.row, col: p.col, superType: cell.superType });
            }
        };

        for (const s of seeds) enqueue(s);

        while (queue.length > 0) {
            const { row, col, superType } = queue.shift()!;
            const affected = this.resolve(superType, field, row, col);
            for (const a of affected) enqueue(a);
        }

        return result;
    }
}
